import 'dart:convert';

class UserData {
  final String userId;
  final String displayName;
  final String email;
  final String? avatarUrl;
  final DateTime lastLogin;

  UserData({
    required this.userId,
    required this.displayName,
    required this.email,
    this.avatarUrl,
    required this.lastLogin,
  });

  Map<String, dynamic> toJson() => {
        'userId': userId,
        'displayName': displayName,
        'email': email,
        'avatarUrl': avatarUrl,
        'lastLogin': lastLogin.toIso8601String(),
      };

  factory UserData.fromJson(Map<String, dynamic> json) => UserData(
        userId: json['userId'] as String,
        displayName: json['displayName'] as String,
        email: json['email'] as String,
        avatarUrl: json['avatarUrl'] as String?,
        lastLogin: DateTime.parse(json['lastLogin'] as String),
      );

  String encode() => jsonEncode(toJson());

  static UserData decode(String source) =>
      UserData.fromJson(jsonDecode(source) as Map<String, dynamic>);
}

// lib/models/auth_tokens.dart
class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;

  AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
  });

  bool get isExpired => DateTime.now().isAfter(expiresAt);

  bool get isNearExpiry =>
      DateTime.now().isAfter(expiresAt.subtract(const Duration(minutes: 5)));
}

// lib/services/secure_token_storage.dart
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class SecureTokenStorage {
  // flutter_secure_storage uses:
  // - iOS: Keychain
  // - Android: EncryptedSharedPreferences (AES-256)
  // - Web: Not truly secure — consider alternative for web
  // - macOS: Keychain
  // - Linux: libsecret
  // - Windows: Windows Credential Manager
  static const FlutterSecureStorage _secureStorage = FlutterSecureStorage(
    aOptions: AndroidOptions(
      encryptedSharedPreferences: true,
    ),
    iOptions: IOSOptions(
      accessibility: KeychainAccessibility.first_unlock_this_device,
    ),
  );

  static const String _accessTokenKey = 'auth_access_token';
  static const String _refreshTokenKey = 'auth_refresh_token';
  static const String _tokenExpiryKey = 'auth_token_expiry';
  static const String _userDataKey = 'auth_user_data_encrypted';

  // Store tokens securely — NEVER in shared_preferences
  Future<void> saveTokens(AuthTokens tokens) async {
    await _secureStorage.write(
        key: _accessTokenKey, value: tokens.accessToken);
    await _secureStorage.write(
        key: _refreshTokenKey, value: tokens.refreshToken);
    await _secureStorage.write(
        key: _tokenExpiryKey, value: tokens.expiresAt.toIso8601String());
  }

  Future<AuthTokens?> getTokens() async {
    final accessToken = await _secureStorage.read(key: _accessTokenKey);
    final refreshToken = await _secureStorage.read(key: _refreshTokenKey);
    final expiryStr = await _secureStorage.read(key: _tokenExpiryKey);

    if (accessToken == null || refreshToken == null || expiryStr == null) {
      return null;
    }

    return AuthTokens(
      accessToken: accessToken,
      refreshToken: refreshToken,
      expiresAt: DateTime.parse(expiryStr),
    );
  }

  // User data contains PII (email, etc.) — store in secure storage
  Future<void> saveUserData(UserData userData) async {
    await _secureStorage.write(
        key: _userDataKey, value: userData.encode());
  }

  Future<UserData?> getUserData() async {
    final encoded = await _secureStorage.read(key: _userDataKey);
    if (encoded == null) return null;
    try {
      return UserData.decode(encoded);
    } catch (_) {
      await _secureStorage.delete(key: _userDataKey);
      return null;
    }
  }

  Future<void> clearAll() async {
    await _secureStorage.delete(key: _accessTokenKey);
    await _secureStorage.delete(key: _refreshTokenKey);
    await _secureStorage.delete(key: _tokenExpiryKey);
    await _secureStorage.delete(key: _userDataKey);
  }

  Future<bool> hasTokens() async {
    final token = await _secureStorage.read(key: _accessTokenKey);
    return token != null;
  }
}

