import 'package:shared_preferences/shared_preferences.dart';

/// shared_preferences is ONLY for non-sensitive user preferences.
/// NEVER store tokens, passwords, PII, or encryption keys here.
class PreferencesStorage {
  static const String _isOnboardedKey = 'pref_is_onboarded';
  static const String _themeKey = 'pref_theme_mode';
  static const String _localeKey = 'pref_locale';
  static const String _lastSessionTimestampKey = 'pref_last_session';
  static const String _biometricEnabledKey = 'pref_biometric_enabled';

  late final SharedPreferences _prefs;
  bool _initialized = false;

  Future<void> init() async {
    if (!_initialized) {
      _prefs = await SharedPreferences.getInstance();
      _initialized = true;
    }
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError(
          'PreferencesStorage not initialized. Call init() first.');
    }
  }

  // Non-sensitive: whether user completed onboarding
  bool get isOnboarded {
    _ensureInitialized();
    return _prefs.getBool(_isOnboardedKey) ?? false;
  }

  Future<void> setOnboarded(bool value) async {
    _ensureInitialized();
    await _prefs.setBool(_isOnboardedKey, value);
  }

  // Non-sensitive: theme preference
  String get themeMode {
    _ensureInitialized();
    return _prefs.getString(_themeKey) ?? 'system';
  }

  Future<void> setThemeMode(String mode) async {
    _ensureInitialized();
    await _prefs.setString(_themeKey, mode);
  }

  // Non-sensitive: locale preference
  String? get locale {
    _ensureInitialized();
    return _prefs.getString(_localeKey);
  }

  Future<void> setLocale(String locale) async {
    _ensureInitialized();
    await _prefs.setString(_localeKey, locale);
  }

  // Non-sensitive: last session timestamp for session management UI
  DateTime? get lastSessionTimestamp {
    _ensureInitialized();
    final ts = _prefs.getString(_lastSessionTimestampKey);
    return ts != null ? DateTime.tryParse(ts) : null;
  }

  Future<void> setLastSessionTimestamp(DateTime timestamp) async {
    _ensureInitialized();
    await _prefs.setString(
        _lastSessionTimestampKey, timestamp.toIso8601String());
  }

  // Non-sensitive: whether biometric login is enabled (the actual
  // biometric credentials are handled by the OS, not stored by us)
  bool get isBiometricEnabled {
    _ensureInitialized();
    return _prefs.getBool(_biometricEnabledKey) ?? false;
  }

  Future<void> setBiometricEnabled(bool value) async {
    _ensureInitialized();
    await _prefs.setBool(_biometricEnabledKey, value);
  }

  Future<void> clearAll() async {
    _ensureInitialized();
    await _prefs.clear();
  }
}

