// lib/services/auth_manager.dart
import 'dart:async';
import 'package:flutter/foundation.dart';
import '../models/auth_tokens.dart';
import '../models/user_data.dart';
import 'secure_token_storage.dart';
import 'preferences_storage.dart';
import 'auth_api_client.dart';

enum AuthState {
  uninitialized,
  authenticated,
  unauthenticated,
  loading,
}

class AuthManager extends ChangeNotifier {
  final SecureTokenStorage _secureStorage;
  final PreferencesStorage _preferencesStorage;
  final AuthApiClient _apiClient;

  AuthState _state = AuthState.uninitialized;
  UserData? _currentUser;
  AuthTokens? _currentTokens;
  Timer? _tokenRefreshTimer;
  String? _lastError;

  AuthManager({
    SecureTokenStorage? secureStorage,
    PreferencesStorage? preferencesStorage,
    AuthApiClient? apiClient,
  })  : _secureStorage = secureStorage ?? SecureTokenStorage(),
        _preferencesStorage = preferencesStorage ?? PreferencesStorage(),
        _apiClient = apiClient ?? AuthApiClient();

  AuthState get state => _state;
  UserData? get currentUser => _currentUser;
  bool get isAuthenticated => _state == AuthState.authenticated;
  bool get isLoading => _state == AuthState.loading;
  String? get lastError => _lastError;

  /// Returns the current valid access token, refreshing if needed.
  /// Returns null if not authenticated.
  Future<String?> getValidAccessToken() async {
    if (_currentTokens == null) return null;

    if (_currentTokens!.isExpired || _currentTokens!.isNearExpiry) {
      try {
        await _refreshTokens();
      } catch (_) {
        await _handleSessionExpired();
        return null;
      }
    }

    return _currentTokens?.accessToken;
  }

  /// Initialize auth manager — call on app startup
  Future<void> initialize() async {
    _state = AuthState.loading;
    notifyListeners();

    try {
      await _preferencesStorage.init();

      // Attempt to restore session from secure storage
      final tokens = await _secureStorage.getTokens();
      final userData = await _secureStorage.getUserData();

      if (tokens != null && userData != null) {
        if (tokens.isExpired) {
          // Try to refresh
          try {
            final newTokens =
                await _apiClient.refreshTokens(tokens.refreshToken);
            await _secureStorage.saveTokens(newTokens);
            _currentTokens = newTokens;
            _currentUser = userData;
            _state = AuthState.authenticated;
            _scheduleTokenRefresh();
            await _preferencesStorage
                .setLastSessionTimestamp(DateTime.now());
          } catch (_) {
            // Refresh failed — session expired
            await _secureStorage.clearAll();
            _state = AuthState.unauthenticated;
          }
        } else {
          // Tokens still valid
          _currentTokens = tokens;
          _currentUser = userData;
          _state = AuthState.authenticated;
          _scheduleTokenRefresh();
          await _preferencesStorage
              .setLastSessionTimestamp(DateTime.now());
        }
      } else {
        _state = AuthState.unauthenticated;
      }
    } catch (e) {
      debugPrint('Auth initialization error: $e');
      _state = AuthState.unauthenticated;
    }

    notifyListeners();
  }

  /// Login with email and password
  Future<bool> login(String email, String password) async {
    _lastError = null;
    _state = AuthState.loading;
    notifyListeners();

    try {
      final result = await _apiClient.login(email, password);

      // Store tokens in SECURE storage (Keychain/EncryptedSharedPreferences)
      await _secureStorage.saveTokens(result.tokens);

      // Store user data in SECURE storage (contains PII)
      await _secureStorage.saveUserData(result.user);

      // Only non-sensitive data in shared_preferences
      await _preferencesStorage.setLastSessionTimestamp(DateTime.now());
      await _preferencesStorage.setOnboarded(true);

      _currentTokens = result.tokens;
      _currentUser = result.user;
      _state = AuthState.authenticated;
      _scheduleTokenRefresh();

      notifyListeners();
      return true;
    } on AuthException catch (e) {
      _lastError = e.message;
      _state = AuthState.unauthenticated;
      notifyListeners();
      return false;
    } catch (e) {
      _lastError = 'An unexpected error occurred. Please try again.';
      _state = AuthState.unauthenticated;
      notifyListeners();
      return false;
    }
  }

  /// Logout — clear all sensitive data
  Future<void> logout() async {
    _state = AuthState.loading;
    notifyListeners();

    try {
      // Invalidate session server-side
      if (_currentTokens != null) {
        try {
          await _apiClient.logout(_currentTokens!.accessToken);
        } catch (_) {
          // Best effort — still clear local data even if server call fails
        }
      }
    } finally {
      _cancelTokenRefreshTimer();

      // Clear ALL sensitive data from secure storage
      await _secureStorage.clearAll();

      _currentTokens = null;
      _currentUser = null;
      _state = AuthState.unauthenticated;

      // Note: We do NOT clear preferences — theme, locale, etc. persist
      // across login/logout cycles. Only sensitive data is cleared.

      notifyListeners();
    }
  }

  /// Force clear everything (e.g., for account deletion)
  Future<void> clearAllData() async {
    _cancelTokenRefreshTimer();
    await _secureStorage.clearAll();
    await _preferencesStorage.clearAll();
    _currentTokens = null;
    _currentUser = null;
    _state = AuthState.unauthenticated;
    notifyListeners();
  }

  Future<void> _refreshTokens() async {
    if (_currentTokens == null) return;

    final newTokens =
        await _apiClient.refreshTokens(_currentTokens!.refreshToken);
    await _secureStorage.saveTokens(newTokens);
    _currentTokens = newTokens;
    _scheduleTokenRefresh();
  }

  void _scheduleTokenRefresh() {
    _cancelTokenRefreshTimer();

    if (_currentTokens == null) return;

    // Refresh 5 minutes before expiry
    final refreshIn = _currentTokens!.expiresAt
        .subtract(const Duration(minutes: 5))
        .difference(DateTime.now());

    if (refreshIn.isNegative) {
      // Already near expiry, refresh now
      _refreshTokens().catchError((_) => _handleSessionExpired());
      return;
    }

    _tokenRefreshTimer = Timer(refreshIn, () {
      _refreshTokens().catchError((_) => _handleSessionExpired());
    });
  }

  void _cancelTokenRefreshTimer() {
    _tokenRefreshTimer?.cancel();
    _tokenRefreshTimer = null;
  }

  Future<void> _handleSessionExpired() async {
    _cancelTokenRefreshTimer();
    await _secureStorage.clearAll();
    _currentTokens = null;
    _currentUser = null;
    _lastError = 'Your session has expired. Please log in again.';
    _state = AuthState.unauthenticated;
    notifyListeners();
  }

  @override
  void dispose() {
    _cancelTokenRefreshTimer();
    super.dispose();
  }
}

