import 'package:flutter/material.dart';
import 'services/auth_manager.dart';
import 'screens/login_screen.dart';
import 'screens/home_screen.dart';
import 'screens/splash_screen.dart';

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  runApp(const MyApp());
}

class MyApp extends StatefulWidget {
  const MyApp({super.key});

  @override
  State<MyApp> createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  late final AuthManager _authManager;

  @override
  void initState() {
    super.initState();
    _authManager = AuthManager();
    _authManager.addListener(_onAuthChanged);
    _authManager.initialize();
  }

  void _onAuthChanged() {
    setState(() {});
  }

  @override
  void dispose() {
    _authManager.removeListener(_onAuthChanged);
    _authManager.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return AuthManagerProvider(
      authManager: _authManager,
      child: MaterialApp(
        title: 'Secure Auth Demo',
        theme: ThemeData(
          colorScheme: ColorScheme.fromSeed(seedColor: Colors.indigo),
          useMaterial3: true,
        ),
        home: _buildHome(),
      ),
    );
  }

  Widget _buildHome() {
    switch (_authManager.state) {
      case AuthState.uninitialized:
      case AuthState.loading:
        return const SplashScreen();
      case AuthState.authenticated:
        return const HomeScreen();
      case AuthState.unauthenticated:
        return const LoginScreen();
    }
  }
}

/// InheritedWidget to provide AuthManager down the tree
class AuthManagerProvider extends InheritedWidget {
  final AuthManager authManager;

  const AuthManagerProvider({
    super.key,
    required this.authManager,
    required super.child,
  });

  static AuthManager of(BuildContext context) {
    final provider =
        context.dependOnInheritedWidgetOfExactType<AuthManagerProvider>();
    assert(provider != null, 'No AuthManagerProvider found in context');
    return provider!.authManager;
  }

  @override
  bool updateShouldNotify(AuthManagerProvider oldWidget) {
    return authManager != oldWidget.authManager;
  }
}

